1	/**
2	 * Factory: select an Embedder by env. Caches a singleton so callers can
3	 * call getEmbedder() repeatedly without rebuilding state (e.g., usage
4	 * counters live on the instance).
5	 *
6	 *   EMBEDDER=voyage   (default) — VoyageEmbedder, voyage-3, 1024 dims
7	 *   EMBEDDER=openai            — OpenAIEmbedder, text-embedding-3-large
8	 *                                 reduced to 1024 dims to match
9	 */
10	import { type Embedder, VoyageEmbedder } from "./embedder.js";
11	import { OpenAIEmbedder } from "./embedderOpenAI.js";
12	
13	export type EmbedderProvider = "voyage" | "openai";
14	
15	let cached: Embedder | null = null;
16	let cachedProvider: EmbedderProvider | null = null;
17	
18	export function getEmbedder(): Embedder {
19	  const provider = resolveProvider();
20	  if (cached && cachedProvider === provider) return cached;
21	
22	  cached = provider === "openai" ? new OpenAIEmbedder() : new VoyageEmbedder();
23	  cachedProvider = provider;
24	  return cached;
25	}
26	
27	/** Test-only: reset the cached singleton. */
28	export function _resetEmbedderCache(): void {
29	  cached = null;
30	  cachedProvider = null;
31	}
32	
33	function resolveProvider(): EmbedderProvider {
34	  const raw = (process.env.EMBEDDER ?? "voyage").toLowerCase();
35	  if (raw === "openai") return "openai";
36	  if (raw === "voyage" || raw === "") return "voyage";
37	  throw new Error(`Unknown EMBEDDER value: ${process.env.EMBEDDER}`);
38	}
39

