  const c = hit.chunk;
  return {
    chunkId: c.id,
    text: c.text,
    heading: c.heading ?? undefined,
    section: c.section ?? undefined,
    path: c.path,
    topics: c.topics ?? [],
    kind: c.kind ?? "",
    score,
    citeOkay: c.citeOkay,
  };
}

function clamp01(x: number): number {
  if (!Number.isFinite(x)) return 0;
  if (x < 0) return 0;
  if (x > 1) return 1;
  return x;
}

